// Extraer y limpiar campos del email Gmail
const item = $input.first().json;

// Extraer remitente
let fuente = '';
let fuente_nombre = '';
try {
  if (item.from && item.from.value && item.from.value.length > 0) {
    fuente = item.from.value[0].address || '';
    fuente_nombre = item.from.value[0].name || fuente;
  } else if (typeof item.from === 'string') {
    fuente = item.from;
    fuente_nombre = item.from;
  }
} catch(e) {
  fuente = String(item.from || '');
  fuente_nombre = fuente;
}

// Extraer cuerpo del email (preferir texto plano, fallback a snippet)
let cuerpo = '';
if (item.text && item.text.length > 100) {
  cuerpo = item.text.substring(0, 8000); // Limitar para no exceder tokens
} else if (item.snippet) {
  cuerpo = item.snippet;
} else if (item.textHtml) {
  // Limpiar HTML básico si no hay texto plano
  cuerpo = item.textHtml
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);
}

// Fecha procesada
const fecha_raw = item.date || new Date().toISOString();
let fecha_iso = '';
try {
  fecha_iso = new Date(fecha_raw).toISOString().split('T')[0];
} catch(e) {
  fecha_iso = new Date().toISOString().split('T')[0];
}

return [{
  json: {
    email_id: item.id || item.threadId || 'unknown',
    fuente: fuente,
    fuente_nombre: fuente_nombre,
    subject: item.subject || '(sin asunto)',
    body_text: cuerpo,
    fecha_raw: fecha_raw,
    fecha_iso: fecha_iso,
    snippet: item.snippet || ''
  }
}];

