// Parsear respuesta de Claude y preparar fila para Google Sheets
const claudeResponse = $input.first().json;
const emailData = $('Extraer Campos Email').first().json;

// Extraer texto de la respuesta
let rawText = '';
try {
  rawText = claudeResponse.content[0].text;
} catch(e) {
  throw new Error('Error al leer respuesta de Claude: ' + JSON.stringify(claudeResponse));
}

// Parsear JSON - manejar casos donde Claude agrega markdown
let analysis;
try {
  // Intento directo
  analysis = JSON.parse(rawText);
} catch(e1) {
  try {
    // Extraer de bloque ```json ... ```
    const match = rawText.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
    if (match) {
      analysis = JSON.parse(match[1]);
    } else {
      // Buscar el JSON por llaves
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        analysis = JSON.parse(jsonMatch[0]);
      } else {
        throw new Error('No JSON found');
      }
    }
  } catch(e2) {
    throw new Error('No se pudo parsear respuesta Claude: ' + rawText.substring(0, 200));
  }
}

// Generar ID único para la noticia
const dateStr = emailData.fecha_iso.replace(/-/g, '');
const fuenteSlug = (analysis.fuente_detectada || emailData.fuente_nombre || emailData.fuente)
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // quitar tildes
  .replace(/[^a-z0-9]/g, '')
  .substring(0, 8);
const timestamp36 = Date.now().toString(36).toUpperCase();
const id_noticia = `NEW-${dateStr}-${fuenteSlug}-${timestamp36}`;

// Score como número
const score = parseInt(analysis.score) || 0;

return [{
  json: {
    id_noticia: id_noticia,
    fuente: analysis.fuente_detectada || emailData.fuente_nombre || emailData.fuente,
    email_origen: emailData.fuente,
    asunto_original: emailData.subject,
    fecha: emailData.fecha_iso,
    resumen: analysis.resumen || '',
    score: score,
    score_razon: analysis.score_razon || '',
    rubro: analysis.rubro || '',
    sugerencia_linkedin: (analysis.linkedin_post || '') + '\n\n' + (analysis.hashtags || ''),
    email_id_gmail: emailData.email_id
  }
}];

// Log de éxito con metadata
const data = $input.first().json;
console.log(`✅ Newsletter procesado: ${data.id_noticia} | Score: ${data.score}/10 | Rubro: ${data.rubro}`);
return $input.all();

// Capturar error y notificar
const error = $input.first().json;
console.error('❌ Error en Newsletter Assistant:', JSON.stringify(error));

return [{
  json: {
    error: true,
    mensaje: error.message || 'Error desconocido',
    workflow: error.execution?.workflowName || 'Newsletter Content Assistant',
    nodo: error.node?.name || 'Desconocido',
    timestamp: new Date().toISOString()
  }
}];
